use std::fmt;
use std::num::ParseIntError;

#[derive(Debug)]
enum AppError {
    ParseError(ParseIntError),
    ValidationError(String),
}

impl fmt::Display for AppError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            AppError::ParseError(e) => write!(f, "Parse error: {e}"),
            AppError::ValidationError(s) => write!(f, "Validation error: {s}"),
        }
    }
}

impl From<ParseIntError> for AppError {
    fn from(e: ParseIntError) -> Self {
        AppError::ParseError(e)
    }
}

fn parse_and_validate(s: &str) -> Result<i32, AppError> {
    let n: i32 = s.parse()?;
    if n < 0 {
        Err(AppError::ValidationError("Number must be non-negative".to_string()))
    } else {
        Ok(n)
    }
}

fn main() {
    println!("{:?}", parse_and_validate("42"));
    println!("{:?}", parse_and_validate("abc"));
    println!("{:?}", parse_and_validate("-5"));
}
